import{_ as s,o as e,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const n="/assets/09-plugin-platform-layers@2x.CulJcCIh.png",u=JSON.parse('{"title":"09 · JetBrains 集成","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/09-jetbrains.md","filePath":"claude-code/09-jetbrains.md"}'),i={name:"claude-code/09-jetbrains.md"};function d(r,t,l,p,g,h){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="_09-·-jetbrains-集成" tabindex="-1">09 · JetBrains 集成 <a class="header-anchor" href="#_09-·-jetbrains-集成" aria-label="Permalink to &quot;09 · JetBrains 集成&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./08-vscode">08 VS Code 集成</a> 把 Claude Code 搬进了 VS Code。这一篇换个阵营——如果你的主力是 IntelliJ IDEA、PyCharm、WebStorm 这类 JetBrains 全家桶，同样有原生插件，玩法既像又不像。下一篇 <a href="./10-desktop">10 桌面 app</a>。</p></blockquote><p>A：「我天天泡在 PyCharm 里，VS Code 那套扩展跟我没关系吧？」</p><p>B：「有原生插件，装一下，<code>Cmd+Esc</code> 就能从编辑器里把 Claude 叫出来。」</p><p>A：「那它跟 VS Code 扩展是一回事？diff、<code>@</code> 提及那些都有？」</p><p>B：「内核是同一个 CLI，但<strong>界面不是同一拨人做的</strong>——有些地方一样，有些地方你得换个姿势。比如它默认是跑在 IDE 自带终端里的，不是一个独立面板。」</p><p>这是用 GoLand 写后端的人常有的疑问，很典型：<strong>JetBrains 用户总担心自己是「二等公民」</strong>，好东西都先给 VS Code。</p><p>说句实话，这担心一半对一半不对。对的地方：JetBrains 插件确实比 VS Code 扩展<strong>更轻</strong>，它是把 CLI 跟 IDE 接通、让信息在两边流动，而不是做一个大而全的图形面板。不对的地方：<strong>该有的核心体验一个没少</strong>。</p><p>这一篇就讲清楚：<strong>怎么装、怎么连、和 VS Code 比差在哪、JetBrains 专属的几个坑（ESC 键、WSL、远程开发）怎么填</strong>。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>在 IntelliJ / PyCharm / WebStorm 等 JetBrains IDE 里装好 Claude Code 插件的完整步骤</li><li>「IDE 内置终端」和「外部终端 <code>/ide</code>」两种连接方式，分别什么时候用</li><li>一张「JetBrains 插件 vs VS Code 扩展」的对照表，外加 JetBrains 专属快捷键</li><li>ESC 键中断失灵、WSL2「检测不到 IDE」、远程开发这三个高频坑的官方解法</li></ul><hr><h2 id="_01-先理清楚-插件到底做了什么" tabindex="-1">01 先理清楚：插件到底做了什么 <a class="header-anchor" href="#_01-先理清楚-插件到底做了什么" aria-label="Permalink to &quot;01 先理清楚：插件到底做了什么&quot;">​</a></h2><p>很多人装完插件一脸懵：<strong>「我装了插件，怎么没看到一个像 VS Code 那样的聊天面板？」</strong></p><p>先给结论：<strong>JetBrains 插件不是一个独立的聊天窗口，它是一座「桥」</strong>。Claude Code 本体还是那个跑在终端里的 CLI，插件干的活是把 IDE 和 CLI 接通——你在编辑器里选中的代码、IDE 报的 lint 错误、Claude 想做的改动，能在「IDE」和「终端里的 Claude」之间自动来回传。</p><p><strong>类比：手机和电脑之间的隔空投送（AirDrop）。</strong> 文件、剪贴板本来各待各的设备上，开了隔空投送两台设备就「认识」了——电脑上复制，手机上直接粘。插件就是 IDE 和 Claude 之间的这条通道：<strong>你在 PyCharm 里选中一段代码，终端里的 Claude 立刻就「看见」了</strong>，不用复制粘贴。</p><p>所以有个关键认知：</p><blockquote><p><strong>在 JetBrains 里，你跟 Claude 对话的地方，是 IDE 自带的集成终端</strong>——不是一个新开的侧边面板。</p></blockquote><p>这是和 VS Code 最大的体感差异：VS Code 扩展给你一个图形对话面板；JetBrains 则让你在内置终端里跑 <code>claude</code>，插件在背后喂上下文。<strong>对话在终端、diff 弹到 IDE 原生查看器</strong>，两边好处都占着，而且几乎零学习成本——<strong>命令、快捷键、<code>/</code> 斜杠命令全是终端那一套</strong>。第一次在 IntelliJ 装插件，本来还会担心要重新适应界面，结果发现<strong>就是熟悉的那个终端 Claude，只是它突然「长了眼睛」，能看到你选了什么、IDE 标红了哪里</strong>。</p><blockquote><p>💡 一句话总结：JetBrains 插件是 IDE 和 CLI 之间的「隔空投送」，<strong>对话在内置终端里发生、diff 弹进 IDE</strong>，不是一个独立聊天面板。</p></blockquote><hr><h2 id="_02-支持哪些-ide-先对个号" tabindex="-1">02 支持哪些 IDE，先对个号 <a class="header-anchor" href="#_02-支持哪些-ide-先对个号" aria-label="Permalink to &quot;02 支持哪些 IDE，先对个号&quot;">​</a></h2><p>JetBrains 是一整个家族，不是单个软件。<strong>好消息是：Claude Code 插件覆盖了主流的几乎全部</strong>。</p><p>官方明确列出的支持名单：</p><table tabindex="0"><thead><tr><th>IDE</th><th>主要语言 / 场景</th></tr></thead><tbody><tr><td><strong>IntelliJ IDEA</strong></td><td>Java / Kotlin，后端、Android 老本行</td></tr><tr><td><strong>PyCharm</strong></td><td>Python，数据、AI、脚本</td></tr><tr><td><strong>WebStorm</strong></td><td>前端 JS / TS</td></tr><tr><td><strong>PhpStorm</strong></td><td>PHP</td></tr><tr><td><strong>GoLand</strong></td><td>Go</td></tr><tr><td><strong>Android Studio</strong></td><td>安卓开发（基于 IntelliJ）</td></tr></tbody></table><p>官方说法是「<strong>适用于大多数</strong> JetBrains IDE」——名单外的 JetBrains IDE（RubyMine、CLion、Rider 等）大概率也能用，但官方没背书，能装上就用、出问题以「未明确支持」对待。</p><p><strong>类比：同一品牌的不同车型，共用一套车机系统。</strong> IntelliJ、PyCharm、WebStorm 就像同厂家的轿车、SUV、跑车，定位不同但<strong>底层是同一个平台</strong>（都构建在 IntelliJ Platform 上）。所以一个插件通吃，<strong>这篇里所有操作步骤，不管你用 IntelliJ 还是 GoLand，菜单路径都一致</strong>。下面演示用 PyCharm。</p><p><img src="'+n+`" alt="一个 Claude Code 插件通吃所有 JetBrains IDE，因为它们共用 IntelliJ 平台底座"></p><p>上图把这层关系画清楚了：最上面的 Claude Code 插件只有一个，向下扇出适配每个 IDE；而 IntelliJ IDEA、PyCharm、WebStorm 等虽各管一门语言，却都坐在同一个 IntelliJ Platform 底座上——所以一个插件装一次，处处能用，安装配置步骤也处处一致。</p><blockquote><p>💡 一句话总结：主流 JetBrains IDE 都支持，<strong>它们共用同一个 IntelliJ 平台底座</strong>——安装和配置步骤在哪个 IDE 里都一模一样。</p></blockquote><hr><h2 id="_03-安装-插件-cli-缺一不可" tabindex="-1">03 安装：插件 + CLI，缺一不可 <a class="header-anchor" href="#_03-安装-插件-cli-缺一不可" aria-label="Permalink to &quot;03 安装：插件 + CLI，缺一不可&quot;">​</a></h2><p>这步最容易出岔子，因为 <strong>JetBrains 集成需要两样东西都到位</strong>：插件，和 Claude Code CLI 本体，少哪个都不行。</p><p><strong>类比：手机 App + 后台账号。</strong> 装了 App（插件）却没注册后台账号（CLI），打开就是个空壳——插件负责界面集成，真正干活的「后台」是 CLI。<strong>所以装插件前先确认 CLI 在。</strong></p><h3 id="第一步-先确认-cli-装好了" tabindex="-1">第一步：先确认 CLI 装好了 <a class="header-anchor" href="#第一步-先确认-cli-装好了" aria-label="Permalink to &quot;第一步：先确认 CLI 装好了&quot;">​</a></h3><p>跟着这个系列从头读的话，第 02 篇就装好 CLI 了。不确定就在任意终端跑：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p><strong>预期输出</strong>：打印出一串版本号，类似 <code>2.x.x (Claude Code)</code>。</p><p>如果提示 <code>command not found</code>，说明 CLI 还没装。回到 <a href="./02-install">02 安装</a> 那篇装一下，或者用官方安装命令（分平台）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS / Linux / WSL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows PowerShell</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">irm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude.ai/install.ps1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> iex</span></span></code></pre></div><blockquote><p>国内提示：安装 CLI、之后的登录授权、以及让 Claude 干活，<strong>全程都要连 Anthropic 的服务，需要魔法上网</strong>。这点和终端版、VS Code 版都一致。</p></blockquote><h3 id="第二步-装-jetbrains-插件" tabindex="-1">第二步：装 JetBrains 插件 <a class="header-anchor" href="#第二步-装-jetbrains-插件" aria-label="Permalink to &quot;第二步：装 JetBrains 插件&quot;">​</a></h3><p>两条路都能走，推荐第一条。</p><p><strong>方式一：IDE 里搜（推荐）</strong></p><ol><li>打开你的 JetBrains IDE</li><li>进 <strong>Settings（设置）→ Plugins（插件）</strong>（Mac 快捷键 <code>Cmd+,</code>，Windows/Linux <code>Ctrl+Alt+S</code>）</li><li>切到 <strong>Marketplace（市场）</strong> 标签</li><li>搜索 <strong>Claude Code</strong></li><li>点 <strong>Install（安装）</strong></li><li><strong>装完务必重启 IDE</strong></li></ol><p><strong>方式二：去插件市场官网装</strong></p><p>直接访问 <a href="https://plugins.jetbrains.com/plugin/27310-claude-code-beta-" target="_blank" rel="noreferrer">JetBrains 插件市场的 Claude Code 页面</a>，按页面指引安装。</p><p>注意插件名带 <strong>[Beta]</strong> 后缀——<strong>说明它还在 Beta 阶段，行为可能随版本变化</strong>（以官方文档为准）。功能能用，但别当板上钉钉的稳定版。</p><h3 id="第三步-重启-ide-别跳过" tabindex="-1">第三步：重启 IDE（别跳过） <a class="header-anchor" href="#第三步-重启-ide-别跳过" aria-label="Permalink to &quot;第三步：重启 IDE（别跳过）&quot;">​</a></h3><p>官方专门强调了一句：</p><blockquote><p><strong>安装插件后，你可能需要完全重启 IDE 才能让它生效。</strong></p></blockquote><p>「完全重启」是彻底退出再打开，不是关个窗口。这个坑很容易栽进去——装完在 IDE 里跑 <code>claude</code>，集成功能死活不激活，以为插件坏了；<strong>彻底退出 IntelliJ 重开，一切正常</strong>。这坑官方也列在「插件不工作」排查第一条，足见多常见。</p><table tabindex="0"><thead><tr><th>❌ 容易踩的坑</th><th>✅ 正确做法</th></tr></thead><tbody><tr><td>只装插件、没装 CLI</td><td>先 <code>claude --version</code> 确认 CLI 在</td></tr><tr><td>装完不重启就用</td><td>装完<strong>完全退出 IDE 再重开</strong></td></tr><tr><td>搜到相似插件随便装</td><td>认准官方的 <strong>Claude Code [Beta]</strong></td></tr><tr><td>重启关窗口了事</td><td>「完全重启」= 彻底退出进程再启动</td></tr></tbody></table><blockquote><p>💡 一句话总结：JetBrains 集成 = <strong>CLI 本体 + 插件</strong>，两样都要装；<strong>装完一定完全重启 IDE</strong>，这是最高频的「装了不生效」原因。</p></blockquote><hr><h2 id="_04-连接-两种姿势-看你从哪启动" tabindex="-1">04 连接：两种姿势，看你从哪启动 <a class="header-anchor" href="#_04-连接-两种姿势-看你从哪启动" aria-label="Permalink to &quot;04 连接：两种姿势，看你从哪启动&quot;">​</a></h2><p>插件装好、IDE 重启完，下一步是把 Claude Code 跟 IDE「连上」。<strong>连上后，选区共享、diff 弹进 IDE、诊断共享才会激活。</strong> 连接方式取决于你<strong>从哪里启动 Claude</strong>。</p><h3 id="姿势一-从-ide-内置终端启动-推荐-自动连" tabindex="-1">姿势一：从 IDE 内置终端启动（推荐，自动连） <a class="header-anchor" href="#姿势一-从-ide-内置终端启动-推荐-自动连" aria-label="Permalink to &quot;姿势一：从 IDE 内置终端启动（推荐，自动连）&quot;">​</a></h3><p>最省事。打开 IDE 自带的集成终端（一般在底部，有个 <strong>Terminal</strong> 标签页），直接跑：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>预期</strong>：Claude Code 启动，<strong>所有集成功能自动激活</strong>，不用任何手动连接动作。因为你在 IDE 的「肚子里」启动，插件天然知道该跟哪个 IDE 接通。</p><p><strong>类比：在自家客厅连 Wi-Fi。</strong> 在家里打开手机自动连上，不用输密码。内置终端启动 Claude 就是这体验——<strong>环境对了，连接自动完成</strong>。</p><h3 id="姿势二-从外部终端启动-用-ide-手动连" tabindex="-1">姿势二：从外部终端启动，用 <code>/ide</code> 手动连 <a class="header-anchor" href="#姿势二-从外部终端启动-用-ide-手动连" aria-label="Permalink to &quot;姿势二：从外部终端启动，用 \`/ide\` 手动连&quot;">​</a></h3><p>如果你习惯用 iTerm、Windows Terminal 这类<strong>独立终端</strong>，那就先启动 Claude，再手动接通：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>然后在 Claude 对话里输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ide</span></span></code></pre></div><p><strong>预期</strong>：Claude 列出检测到的 JetBrains IDE，选中对应的那个，连接建立、功能激活。<strong>类比：在别人家连 Wi-Fi</strong>，得手动选网络——<code>/ide</code> 就是这个动作。</p><h3 id="一个容易忽略的前提-从项目根目录启动" tabindex="-1">一个容易忽略的前提：从项目根目录启动 <a class="header-anchor" href="#一个容易忽略的前提-从项目根目录启动" aria-label="Permalink to &quot;一个容易忽略的前提：从项目根目录启动&quot;">​</a></h3><p>不管哪种姿势，官方都强调：</p><blockquote><p><strong>如果你希望 Claude 能访问和 IDE 相同的文件，请从与 IDE 项目根目录相同的目录启动 Claude Code。</strong></p></blockquote><p>说白了：<strong>IDE 打开的是哪个项目，就在那个项目的根目录下启动 <code>claude</code></strong>。在 <code>~/Downloads</code> 这种目录启动，Claude 看到的文件就和 IDE 里的项目对不上号了。用内置终端启动天然满足这点——这也是<strong>推荐姿势一</strong>的另一个原因。</p><table tabindex="0"><thead><tr><th>启动来源</th><th>连接方式</th><th>项目目录</th></tr></thead><tbody><tr><td><strong>IDE 内置终端</strong></td><td>自动激活，无需操作</td><td>默认就在项目根目录 ✅</td></tr><tr><td><strong>外部终端</strong>（iTerm 等）</td><td>手动跑 <code>/ide</code> 选 IDE</td><td>需自己 <code>cd</code> 到项目根目录</td></tr></tbody></table><p>一般<strong>全程用 IDE 内置终端</strong>就够了——连接自动完成、目录天然对齐、终端和代码同窗口，<code>Cmd+Esc</code> 一按就在两者间跳。除非手头已经开着外部终端在跑别的，才用 <code>/ide</code> 临时接一下。</p><blockquote><p>💡 一句话总结：IDE 内置终端启动 = <strong>自动连、目录天然对齐</strong>（推荐）；外部终端启动 = <strong>跑 <code>/ide</code> 手动连</strong>。无论哪种，都从项目根目录启动。</p></blockquote><hr><h2 id="_05-它能干什么-五个集成功能" tabindex="-1">05 它能干什么：五个集成功能 <a class="header-anchor" href="#_05-它能干什么-五个集成功能" aria-label="Permalink to &quot;05 它能干什么：五个集成功能&quot;">​</a></h2><p>连上之后，插件给的「增益」官方列了五个，逐一说，重点看和 VS Code 的差异，汇总看本节末的对照表。</p><ul><li><strong>① 快速启动</strong>：编辑器里按 <code>Cmd+Esc</code>（Mac）/ <code>Ctrl+Esc</code>（Windows/Linux）直接打开 Claude，也可点 UI 里的按钮。<strong>这个用得最勤</strong>——写着代码想问一句，不用鼠标点终端标签，一个快捷键焦点就过去了。</li><li><strong>② 选区上下文共享</strong>：<strong>IDE 里当前选中的代码、或打开的标签页，自动共享给 Claude</strong>。选中一段问「这段为什么报错」，它知道你指哪段。</li><li><strong>③ 文件引用快捷键</strong>：按 <code>Cmd+Option+K</code>（Mac）/ <code>Alt+Ctrl+K</code>（Linux/Windows）插入一条文件引用，形如 <code>@src/auth.ts#L1-99</code>，<strong>带路径和行号</strong>，让 Claude 精确定位。</li><li><strong>④ Diff 查看</strong>：代码改动<strong>直接在 IDE 的 diff 查看器里展示</strong>，而非终端里用文本符号画（默认不一定开，得设 <code>auto</code>，下节讲）。</li><li><strong>⑤ 诊断共享</strong>：IDE 的 lint 警告、语法错误那些红线黄线，<strong>自动共享给 Claude</strong>，它能直接「看到」标红了哪里，不用你复述报错。</li></ul><p>两个安全 / 易错点单独拎出来：</p><blockquote><p>⚠️ <strong>安全</strong>（和 VS Code 一致）：如果文件命中你设的 <a href="./20-permissions"><code>Read</code> 拒绝规则</a>，它的选区共享会被拦住、不发给 Claude（以官方文档为准）。<code>.env</code> 这类敏感文件建议加上。</p><p>⚠️ <strong>易错</strong>：文件引用快捷键和 VS Code 不一样——VS Code 是 <code>Option+K</code> / <code>Alt+K</code>，JetBrains 多一个键，是 <code>Cmd+Option+K</code> / <code>Alt+Ctrl+K</code>，从 VS Code 切过来最容易按错。</p></blockquote><p>诊断共享这点体会最深。JetBrains 的代码检查本就是业界最强之一——搁以前得把标红的报错复制给终端 Claude，现在它直接读得到。<strong>比如 PyCharm 标了一个「未使用的导入」加几个类型不匹配的黄线，只说一句「把 IDE 标出来的问题修一下」，它就照着诊断一条条修了</strong>，不用你贴一行报错。</p><table tabindex="0"><thead><tr><th>集成功能</th><th>JetBrains</th><th>VS Code</th><th>备注</th></tr></thead><tbody><tr><td>快速启动</td><td><code>Cmd/Ctrl+Esc</code></td><td><code>Cmd/Ctrl+Esc</code></td><td>一致</td></tr><tr><td>选区 / 标签共享</td><td>✅ 自动</td><td>✅ 自动</td><td>一致</td></tr><tr><td>文件引用快捷键</td><td><code>Cmd+Option+K</code> / <code>Alt+Ctrl+K</code></td><td><code>Option+K</code> / <code>Alt+K</code></td><td><strong>不同！</strong></td></tr><tr><td>Diff 弹进 IDE</td><td>✅（需设 <code>auto</code>）</td><td>✅</td><td>一致</td></tr><tr><td>诊断共享</td><td>✅ 自动</td><td>✅ 自动</td><td>一致</td></tr><tr><td>对话界面形态</td><td><strong>IDE 内置终端</strong></td><td><strong>独立图形面板</strong></td><td><strong>核心差异</strong></td></tr></tbody></table><blockquote><p>💡 一句话总结：五大增益里选区共享、诊断共享、diff 弹进 IDE 和 VS Code 基本一致；<strong>最大差异是对话跑在内置终端</strong>，还有<strong>文件引用快捷键多按一个键</strong>。</p></blockquote><hr><h2 id="_06-配置-把-diff-调出来-再调插件" tabindex="-1">06 配置：把 diff 调出来，再调插件 <a class="header-anchor" href="#_06-配置-把-diff-调出来-再调插件" aria-label="Permalink to &quot;06 配置：把 diff 调出来，再调插件&quot;">​</a></h2><p>装好连上还不够，有两处配置值得花两分钟调一下，体验差很多。</p><h3 id="配置一-把-diff-工具设成-auto-重要" tabindex="-1">配置一：把 diff 工具设成 <code>auto</code>（重要） <a class="header-anchor" href="#配置一-把-diff-工具设成-auto-重要" aria-label="Permalink to &quot;配置一：把 diff 工具设成 \`auto\`（重要）&quot;">​</a></h3><p>前面说过 diff 能弹进 IDE，但<strong>这取决于一个配置项</strong>。在 Claude Code 里跑 <code>/config</code>，找到 diff 工具（diff tool），设为 <strong><code>auto</code></strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/config</span></span></code></pre></div><table tabindex="0"><thead><tr><th>取值</th><th>效果</th></tr></thead><tbody><tr><td><strong><code>auto</code></strong></td><td>改动<strong>在 IDE 的 diff 查看器里</strong>并排显示（推荐）</td></tr><tr><td><strong><code>terminal</code></strong></td><td>改动<strong>留在终端里</strong>用文本符号画</td></tr></tbody></table><p>这里强烈建议设 <code>auto</code>——既然用了 IDE，就把 JetBrains 那个好用的并排 diff 视图利用起来，终端文本 diff 在改动一多时真费眼。</p><h3 id="配置二-插件设置-settings-→-tools-→-claude-code-beta" tabindex="-1">配置二：插件设置（Settings → Tools → Claude Code [Beta]） <a class="header-anchor" href="#配置二-插件设置-settings-→-tools-→-claude-code-beta" aria-label="Permalink to &quot;配置二：插件设置（Settings → Tools → Claude Code \\[Beta]）&quot;">​</a></h3><p>插件本身的设置藏在 <strong>Settings → Tools → Claude Code [Beta]</strong> 里。几个值得知道的：</p><ul><li><strong>Claude command（Claude 命令路径）</strong>：默认 <code>claude</code>；如果你的 <code>claude</code> 不在标准 PATH 里，可填绝对路径（如 <code>/usr/local/bin/claude</code>）或 <code>npx @anthropic-ai/claude-code</code>。<strong>点 Claude 图标提示「command not found」时，多半就是这里要配。</strong></li><li><strong>抑制「Claude 命令未找到」的通知</strong>：嫌提示烦可以关掉。</li><li><strong>启用 Option+Enter 多行输入</strong>（仅 macOS）：开启后提示框里 <code>Option+Enter</code> 插入换行。<strong>Option 键被意外捕获、影响打字就关掉它</strong>，改完需重启终端。</li><li><strong>启用自动更新</strong>：自动检查并安装插件更新，重启时应用。</li></ul><p>这几项里<strong>最该记的是最上面那行 <code>Claude command</code> 路径</strong>——点 Claude 图标报「command not found」，十有八九就是它要配。</p><blockquote><p>💡 WSL 用户特别注意：把 Claude 命令设成 <code>wsl -d Ubuntu -- bash -lic &quot;claude&quot;</code>（把 <code>Ubuntu</code> 换成你的 WSL 发行版名）。</p></blockquote><blockquote><p>💡 一句话总结：进 Claude Code 跑 <code>/config</code> 把 diff 设成 <strong><code>auto</code></strong>，再去 <strong>Settings → Tools → Claude Code [Beta]</strong> 调插件——其中 <strong>Claude command 路径</strong>是排查「命令未找到」的关键。</p></blockquote><hr><h2 id="_07-jetbrains-用户专属的三个坑" tabindex="-1">07 JetBrains 用户专属的三个坑 <a class="header-anchor" href="#_07-jetbrains-用户专属的三个坑" aria-label="Permalink to &quot;07 JetBrains 用户专属的三个坑&quot;">​</a></h2><p>下面这三个坑，是 JetBrains 用户<strong>比 VS Code 用户更容易撞上</strong>的，官方单独列了解法。</p><h3 id="坑一-esc-键中断失灵" tabindex="-1">坑一：ESC 键中断失灵 <a class="header-anchor" href="#坑一-esc-键中断失灵" aria-label="Permalink to &quot;坑一：ESC 键中断失灵&quot;">​</a></h3><p>JetBrains 终端有个老毛病：<strong>你想按 <code>ESC</code> 中断 Claude 正在跑的操作，结果焦点「啪」一下跳到编辑器去了，操作没断成。</strong> 原因是它默认把 <code>ESC</code> 绑成了「把焦点移到编辑器」。解法：</p><ol><li>进 <strong>Settings → Tools → Terminal</strong></li><li>二选一：取消勾选 <strong>「使用 Escape 将焦点移动到编辑器」</strong>（Move focus to the editor with Escape），或点「配置终端快捷键」删掉「切换焦点到编辑器」（Switch focus to Editor）这个绑定</li><li>应用更改</li></ol><p>改完 <code>ESC</code> 就能正常中断了。<strong>强烈建议装完就顺手改掉</strong>——不然某次 Claude 跑飞了你想叫停，按 <code>ESC</code> 没反应，那一下是真急。</p><h3 id="坑二-wsl2-提示「未检测到可用的-ide」" tabindex="-1">坑二：WSL2 提示「未检测到可用的 IDE」 <a class="header-anchor" href="#坑二-wsl2-提示「未检测到可用的-ide」" aria-label="Permalink to &quot;坑二：WSL2 提示「未检测到可用的 IDE」&quot;">​</a></h3><p>在 WSL2 上用 Claude Code + JetBrains IDE，跑 <code>/ide</code> 经常报 <strong>「No available IDEs detected」</strong>。<strong>根因不是插件坏了</strong>，而是 WSL2 的 NAT 网络或 Windows 防火墙，把「WSL2 里的 Claude」和「Windows 上的 IDE」的连接挡了（WSL1 不受影响）。官方给了两个方案，<strong>推荐方案一（放行防火墙）</strong>，因为它不动现有网络模式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第一步：在 WSL shell 里查 IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 假设输出 172.21.123.45，记下子网 172.21.0.0/16</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第二步：以管理员身份开 PowerShell，建防火墙规则（IP 范围按你的子网改）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">New-NetFirewallRule</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DisplayName </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Allow WSL2 Internal Traffic&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Direction Inbound </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Protocol TCP </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Action Allow </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RemoteAddress </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">172.21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LocalAddress </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">172.21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span></span></code></pre></div><p>然后<strong>重启 IDE 和 Claude Code</strong> 让规则生效。</p><p>方案二是把 WSL2 切成「镜像网络」（需 Windows 11 22H2 或更高），在 Windows 用户目录的 <code>.wslconfig</code> 里加 <code>[wsl2]</code> 段、设 <code>networkingMode=mirrored</code>，再 <code>wsl --shutdown</code> 重启。<strong>用 Windows 10 的别折腾镜像网络，直接用方案一。</strong></p><h3 id="坑三-远程开发-插件得装在「远程主机」" tabindex="-1">坑三：远程开发，插件得装在「远程主机」 <a class="header-anchor" href="#坑三-远程开发-插件得装在「远程主机」" aria-label="Permalink to &quot;坑三：远程开发，插件得装在「远程主机」&quot;">​</a></h3><p>如果你用 JetBrains 的 <strong>远程开发（Remote Development）</strong>——本地客户端连到远程服务器写代码——有个反直觉的点：</p><blockquote><p><strong>插件必须装在「远程主机」上，不是装在你本地的客户端机器上。</strong></p></blockquote><p>安装路径是 <strong>Settings → Plugin (Host)</strong>。常见的翻车是在本地客户端装了插件，怎么都连不上，折腾半天才发现装错地方。<strong>记住：Claude 实际在哪台机器干活，插件就装哪台。</strong> 远程开发里干活的是远程主机，插件就归它。</p><table tabindex="0"><thead><tr><th>坑</th><th>一句话解法</th></tr></thead><tbody><tr><td><strong>ESC 不能中断</strong></td><td>Settings → Tools → Terminal，取消「Escape 移焦点到编辑器」</td></tr><tr><td><strong>WSL2 检测不到 IDE</strong></td><td>放行 Windows 防火墙（推荐）或切镜像网络，然后重启</td></tr><tr><td><strong>远程开发连不上</strong></td><td>插件装在<strong>远程主机</strong>（Settings → Plugin (Host)），不是本地客户端</td></tr></tbody></table><blockquote><p>💡 一句话总结：ESC 失灵改终端快捷键、WSL2 检测不到放行防火墙、远程开发插件装远程主机——<strong>这三个是 JetBrains 专属高频坑，装完顺手把 ESC 那个改掉</strong>。</p></blockquote><hr><h2 id="_08-动手环节-10-分钟在-jetbrains-里跑通全流程" tabindex="-1">08 动手环节：10 分钟在 JetBrains 里跑通全流程 <a class="header-anchor" href="#_08-动手环节-10-分钟在-jetbrains-里跑通全流程" aria-label="Permalink to &quot;08 动手环节：10 分钟在 JetBrains 里跑通全流程&quot;">​</a></h2><p>下面这套从零走一遍，每步都给了「你该看到什么」，照着做就能自验。<strong>用 PyCharm 演示，其他 JetBrains IDE 步骤完全一样。</strong></p><p><strong>第 0 步：确认 CLI 在</strong> —— 跑 <code>claude --version</code>，<strong>预期</strong>打印版本号（如 <code>2.x.x (Claude Code)</code>）；报 <code>command not found</code> 就先回 <a href="./02-install">02 安装</a>。</p><p><strong>第 1 步：装插件并重启</strong> —— PyCharm → Settings → Plugins → Marketplace，搜 <code>Claude Code</code> → Install，<strong>完全退出 PyCharm 再重开</strong>。<strong>预期</strong>重启后 Settings → Tools 下能看到 <strong>Claude Code [Beta]</strong>。</p><p><strong>第 2 步：建个最小练手项目</strong> —— 新建文件 <code>demo.py</code>：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> greet</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(name):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hello &quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(greet(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;world&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre></div><p><strong>第 3 步：从 IDE 内置终端启动 Claude</strong> —— 打开 PyCharm 底部的 <strong>Terminal</strong> 标签跑 <code>claude</code>。<strong>预期</strong>集成功能自动激活（内置终端启动，无需 <code>/ide</code>）；首次会引导你登录 Anthropic 账户，浏览器完成授权。</p><p><strong>第 4 步：把 diff 设成 <code>auto</code></strong> —— 在 Claude 里跑 <code>/config</code>，把 diff 工具设为 <code>auto</code>，这样下一步改动会弹进 PyCharm 的 diff 查看器。</p><p><strong>第 5 步：选中代码 + 提问，验证选区共享</strong></p><p>在编辑器里<strong>选中 <code>greet</code> 函数那两行</strong>，回到 Claude 终端，输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这段选中的函数有什么可以改进的地方？</span></span></code></pre></div><p><strong>预期</strong>：Claude 基于你选中的两行作答（可能建议用 f-string、加类型注解）——<strong>它没反问你「哪个函数」，说明选区共享生效了</strong>。这是验证「隔空投送」通没通的关键一步。</p><p><strong>第 6 步：让它改，看 diff 弹进 IDE</strong></p><p>接着输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我把它改成用 f-string，并加上类型注解</span></span></code></pre></div><p><strong>预期</strong>：因为上一步设了 <code>auto</code>，改动<strong>在 PyCharm 的 diff 查看器里</strong>并排显示——左边原始 <code>return &quot;Hello &quot; + name</code>，右边改后 <code>return f&quot;Hello {name}&quot;</code>，签名也加了类型注解。看清楚了再接受。</p><p>跑到这步，<strong>插件装好、CLI 连通、选区共享、diff 弹进 IDE 这四件核心你就都验过一遍了</strong>。要是第 5 步它反问你哪个函数、或第 6 步 diff 没弹进 IDE，回头按第 03、04、06 节查。</p><hr><h2 id="_09-小结" tabindex="-1">09 小结 <a class="header-anchor" href="#_09-小结" aria-label="Permalink to &quot;09 小结&quot;">​</a></h2><p>这一篇把 Claude Code 装进了 JetBrains 全家桶，核心就这几件事：</p><ul><li><strong>插件是「桥」不是「面板」</strong>：它把 IDE 和 CLI 接通，<strong>对话跑在 IDE 内置终端、diff 弹进 IDE 原生查看器</strong>，不像 VS Code 给你一个独立聊天面板。</li><li><strong>装要装两样</strong>：CLI 本体 + 插件，缺一不可；<strong>装完一定完全重启 IDE</strong>，这是最高频的「装了不生效」原因。</li><li><strong>连有两种姿势</strong>：IDE 内置终端启动自动连（推荐）、外部终端跑 <code>/ide</code> 手动连；都从项目根目录启动。</li><li><strong>三个专属坑</strong>：ESC 中断失灵（改终端快捷键）、WSL2 检测不到 IDE（放行防火墙）、远程开发插件装远程主机。</li></ul><p>你现在应该能：在自己的 JetBrains IDE 里独立装好插件、把 Claude 和 IDE 连通、用选区共享把上下文喂准、让改动弹进 IDE 的 diff 查看器审阅。<strong>JetBrains 用户不是二等公民——该有的核心体验一个没少。</strong></p><p>到这里，VS Code 和 JetBrains 两大 IDE 阵营都覆盖了。<strong>它们的共同点是：都要先有一个 IDE，再把 Claude 接进去。</strong> 那如果你压根不想开 IDE，只想要一个独立的、开箱即用的 Claude 客户端呢？</p><hr><p>下一篇 <strong>10 桌面 app（Desktop）</strong>——Claude Code 还有个<strong>独立的桌面应用</strong>，不依附任何编辑器，双击就能用。我们看看它适合什么人、和 IDE 集成版怎么取舍，以及它有哪些 IDE 版给不了的便利。</p>`,143)])])}const k=s(i,[["render",d]]);export{u as __pageData,k as default};
